"""
MKT Original Commentary — Genesis chapters 7–9
Run: python3 scripts/zc-original-genesis-7-9.py

Source data used:
- data/interlinear/genesis.json
- data/translation/glossary-hebrew.json
- data/translation/notes/genesis.json (token-level data)
- data/translation/draft/mediating/genesis.json (MKT text)

Key decisions:
- Ch 7:11 "fountains of the great deep" + "windows of heaven": the flood is the
  deliberate reversal of the creation-separation of waters in Gen 1:6-7; tehom
  (deep) returns as uncreation; the terms are technical callbacks to 1:2, 6-9
- Ch 8:1 "God remembered": zakar in the covenant sense -- not memory recovering
  from forgetting but active, faithful attention; recurs at every covenant crisis
- Ch 8:1 "wind over the earth": ruach echoes 1:2, signaling re-creation begins
- Ch 8:21 yetser: same word as Gen 6:5 (every inclination of the heart was only
  evil); God's post-flood promise is given despite unchanged human nature, which
  is why it must be covenant rather than human-moral-improvement
- Ch 9:4 blood/nephesh: the blood prohibition is grounded in nephesh (life/soul)
  being in the blood (Lev 17:11, 14 make this explicit); the Noahic law anticipates
  Levitical theology
- Ch 9:6 imago dei: the most explicit statement that the image-of-God status is the
  ground for prohibiting murder; image-bearing continues after the Fall
- Ch 9:22 "saw the nakedness": galah erwat + the Levitical parallel suggests a
  violation beyond mere looking; the curse on Canaan (not Ham) reflects the
  patriarchal curse-formula falling on descendants, not direct agent
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "7": {
    "1": '<p><strong>צַדִּיק</strong> (<em>ṣaddîq</em>) — "righteous." Noah is found righteous <strong>לְפָנַי</strong> (<em>lĕpānay</em>), "before me" — in the divine sight, not merely by human standards. The same positional phrase appears in 17:1 (Abram told to walk before God) and 48:15 (God before whom my fathers walked). Righteousness here is relational and covenantal rather than morally absolute — Noah stands upright in God\'s covenantal sight in a generation that does not. The Qal perfect <em>rāʾîtî</em> ("I have seen") presents this as God\'s already-completed assessment.</p>',
    "2": '<p><strong>טָהוֹר</strong> (<em>ṭāhôr</em>) — "clean," and <strong>לֹא טָהוֹר</strong> (<em>lōʾ ṭāhôr</em>) — "not clean." The Levitical purity categories (Lev 11; Deut 14) are here anticipated without explanation — Noah already knows which animals are clean. The sevenfold and twofold distinction (seven pairs of clean, one pair of unclean) has sacrificial logic: Noah will offer burnt offerings from the clean animals (8:20), requiring a surplus so the species survives the sacrifice. The text assumes pre-Sinaitic knowledge of clean/unclean categories.</p>',
    "3": '<p>The focus on "seven pairs" of birds mirrors the clean-animal provision of v. 2. <strong>לְחַיּוֹת זֶרַע</strong> (<em>lĕḥayyôt zeraʿ</em>) — "to keep alive seed/offspring upon the face of the earth" — the purpose clause frames the ark as a preservation vehicle rather than merely a survival vessel. The word <em>zeraʿ</em> (seed/offspring) will carry the promise in 3:15 and 12:7; here it is the mechanism of biological continuity across the flood.</p>',
    "4": '<p><strong>אֶמְחֶה</strong> (<em>ʾemḥeh</em>) — "I will blot out/wipe away" — from <em>māḥāh</em>, the same verb used in Exod 32:32-33 (blotting from the book of life) and Num 5:23 (blotting out the words of the curse). The verb is an erasure-word — the flood is presented as divine erasure of the corrupted creation. <strong>כָּל-הַיְקוּם</strong> (<em>kol-hayyĕqûm</em>) — "all the living substance/all that exists" — a comprehensive term covering all animate life created on the land.</p>',
    "5": '<p><strong>וַיַּעַשׂ נֹחַ כְּכֹל אֲשֶׁר-צִוָּהוּ יְהוָה</strong> — "and Noah did according to all that the LORD commanded him." The obedience formula closes the divine speech. This is the standard completeness formula used for tabernacle construction (Exod 40:16: "Moses did everything just as the LORD commanded him") — Noah\'s compliance is total and unconditional, with no recorded question or objection.</p>',
    "6": '<p><strong>בֶּן-שֵׁשׁ מֵאוֹת שָׁנָה</strong> — "son of six hundred years" — the Hebrew idiom for age uses <em>ben</em> (son of) with the number. The precise chronology beginning here (vv. 6, 11) continues through 8:13-14 with specific month and day references — the flood narrative uses a calendrical precision absent from the creation account. The dating grounds the flood in real time and history rather than mythological timelessness.</p>',
    "7": '<p><strong>מִפְּנֵי מֵי הַמַּבּוּל</strong> (<em>mippĕnê mê hammabbûl</em>) — "from before the waters of the flood." The preposition phrase <em>mippĕnê</em> (from before/because of) indicates motivation — they entered the ark in anticipation of and flight from the coming waters. <em>Mabbûl</em> (flood, deluge) is a specific technical term for this event; it appears only in Genesis 6-11 and Ps 29:10 in the entire OT, suggesting it is a term of art for the Noahic flood specifically.</p>',
    "8": '<p>The verse restates the animal categories (clean/unclean, birds, all creeping things) to match the command of vv. 2-3. The structural repetition (command → execution) is deliberate narrative technique throughout the Pentateuch — the tabernacle instructions and their execution (Exod 25-31; 35-40) follow the same pattern. The repetition signals total compliance and provides a legal/narrative completeness to the account.</p>',
    "9": '<p><strong>שְׁנַיִם שְׁנַיִם</strong> (<em>šĕnayim šĕnayim</em>) — "two by two," the distributive construction by doubling the number. <strong>כַּאֲשֶׁר צִוָּה אֱלֹהִים אֶת-נֹחַ</strong> — "as God commanded Noah." The shift from YHWH (v. 5) to <em>ʾĕlōhîm</em> here may reflect a different source perspective or may alternate naturally; in context both refer to the same God. The divine-command/animal-compliance motif continues: the animals come as if directed.</p>',
    "10": '<p><strong>מֵי הַמַּבּוּל</strong> — "the waters of the flood." The waw-consecutive (<em>wayyĕhî</em>) marks the precise temporal fulfillment of the seven-day prediction in v. 4. The short verse is a hinge: it closes the preparation sequence and opens the flood sequence. The seven-day wait before the flood echoes the seven-day creation week — the flood begins on a seven-count, structurally parallel to creation\'s seven-day span.</p>',
    "11": '<p><strong>נִבְקְעוּ כָּל-מַעְיְנֹת תְּהוֹם רַבָּה</strong> (<em>nibqĕʿû kol-maʿyĕnōt tĕhôm rabbāh</em>) — "all the fountains of the great deep burst open." <em>Tĕhôm</em> (the deep) is the word used in 1:2 — the primordial unformed deep over which God\'s spirit hovered. Its eruption here is the deliberate reversal of God\'s work in 1:6-9: the waters separated above and below in creation are now recombined. The flood is theologically un-creation — the separation established on days 2-3 is undone. <strong>אֲרֻבֹּת הַשָּׁמַיִם נִפְתָּחוּ</strong> — "the windows/floodgates of heaven were opened" — the upper waters above the firmament (1:7) now pour through their openings. Both cosmic water-sources open simultaneously: the flood is as total as creation was total.</p>',
    "12": '<p><strong>אַרְבָּעִים יוֹם וְאַרְבָּעִים לָיְלָה</strong> — "forty days and forty nights." The number forty is associated throughout the OT with periods of testing and transition: Moses on Sinai (Exod 24:18; 34:28; Deut 9:9-25); Israel in the wilderness (Num 14:33-34; Deut 8:2-4); Elijah\'s journey to Horeb (1 Kgs 19:8); Jesus\'s temptation (Matt 4:2; par.). The forty-day rainfall is the initiating act; the waters will continue for 150 days (v. 24).</p>',
    "13": '<p>The verse reiterates the ark\'s entry on "that very day" (<em>bĕʿeṣem hayyôm hazzeh</em>) — the same phrase used of the Exodus departure from Egypt in Exod 12:41 and the circumcision of Abraham in 17:23. The phrase marks singular historical events that happen at precisely the right time in God\'s plan. The naming of Noah\'s sons (Shem, Ham, Japheth) is here more than genealogical filler — they will structure the Table of Nations in ch. 10.</p>',
    "14": '<p><strong>לְמִינֵהוּ</strong> — "according to its kind" — the creation category from ch. 1 (1:11, 12, 21, 24, 25) recurs here. The ark preserves what creation established: the kinds remain distinct across the flood. The comprehensive listing (wild animals, livestock, creeping things, birds) mirrors the creation sequence of days 5-6 — the ark carries forward the entire creational taxonomy.</p>',
    "15": '<p><strong>רוּחַ חַיִּים</strong> (<em>rûaḥ ḥayyîm</em>) — "breath of life." The same phrase used in 2:7 (God breathed the breath of life into Adam). Here it describes what all creatures that entered the ark possessed — the divine animating principle that makes them alive. The creatures saved are precisely those who bear this divine breath; all others will lose it in the flood.</p>',
    "16": '<p><strong>וַיִּסְגֹּר יְהוָה בַּעֲדוֹ</strong> (<em>wayyisgōr YHWH baʿăḏô</em>) — "and the LORD shut him in." The verb <em>sāgar</em> (to shut, close) in the Qal: God personally seals the ark. This is the only divine action in the flood narrative that is not mediated through human or natural agency — God directly shuts the door. The personal closure signals total divine protection: what God seals cannot be opened by the waters outside. The preposition <em>baʿăḏô</em> (on his behalf, for him) carries a protective nuance — shut in for his safety.</p>',
    "17": '<p>The waw-consecutive sequence continues the rising flood narrative. <strong>וַיִּגְבְּהוּ</strong> (<em>wayyigbĕhû</em>) — "they rose/grew high" — the same root as <em>gābôah</em> (high, tall, exalted) used of God\'s height and mountains. The ark being lifted (<em>wayyārām</em>) on the increasing waters uses <em>rûm</em> (to rise, be lifted) — the same verb for exaltation elsewhere. The ark rises as the world is submerged — saved precisely by the waters that destroy.</p>',
    "18": '<p><strong>וַתֵּלֶךְ הַתֵּבָה עַל-פְּנֵי הַמָּיִם</strong> (<em>wattēlek hattēbāh ʿal-pĕnê hammāyim</em>) — "and the ark moved on the surface of the waters." <em>Hālaḵ</em> (to walk/go) applied to the ark: it moves without human direction, propelled by the waters rather than navigated by crew. The phrase <em>ʿal-pĕnê hammāyim</em> (on the face/surface of the waters) repeats the construction of 1:2 (the Spirit hovered over <em>pĕnê hammāyim</em>) — the ark floats where the Spirit once hovered.</p>',
    "19": '<p>The emphatic triple intensification: <strong>מְאֹד מְאֹד</strong> (<em>mĕʾōḏ mĕʾōḏ</em>) — "very greatly" (double <em>mĕʾōḏ</em>, an intensification beyond what appears elsewhere in Genesis). All the high mountains under the whole heavens (<em>kol-hehārîm haggĕbōhîm tǎḥat kol-haššāmāyim</em>) — the sweep is deliberately total. The flood is geographically comprehensive in the text\'s own self-description.</p>',
    "20": '<p><strong>חֲמֵשׁ עֶשְׂרֵה אַמָּה מִלְמַעְלָה גָּבְרוּ הַמָּיִם</strong> — "fifteen cubits upward the waters prevailed." A cubit is approximately 18 inches/45 cm — fifteen cubits = about 22 feet/7 meters above the highest mountains. The measurement may have a practical dimension: the ark\'s draft (how deep it sat in water) was probably about 15 cubits (half of the 30-cubit height in 6:15), so the water level at 15 cubits above the highest mountains means the ark barely clears them — a narrative detail that emphasizes the totality of the inundation while explaining why the ark was not grounded on mountaintops earlier.</p>',
    "21": '<p><strong>וַיִּגְוַע</strong> (<em>wayyigwaʿ</em>) — "perished/died" — from <em>gāwaʿ</em>, to expire, breathe one\'s last. The same verb is used of the deaths of Ishmael (25:17), Isaac (35:29), Jacob (49:33), and Aaron (Num 20:26, 28) — a dignified death verb, here applied at mass scale to the entire animal creation. The comprehensive list (birds, livestock, wild animals, swarming creatures, all people) mirrors the creation inventory of days 5-6 in reverse — creation is being unmade in the same order it was made.</p>',
    "22": '<p><strong>כֹּל אֲשֶׁר נִשְׁמַת-רוּחַ חַיִּים בְּאַפָּיו</strong> (<em>kōl ʾăšer nišmat-rûaḥ ḥayyîm bĕʾappāyw</em>) — "all in whose nostrils was the breath (<em>nišmāh</em>) of the spirit of life." This combines both terms for divine animating breath: <em>nišmāh</em> (the breath of God breathed into Adam, 2:7) and <em>rûaḥ ḥayyîm</em> (spirit of life, 7:15). Those who die are precisely those who bore the God-given animating breath — the flood is the withdrawal of the divine life-principle from the land-creatures, leaving only those preserved in the ark.</p>',
    "23": '<p><strong>וַיִּמַח</strong> (<em>wayyimaḥ</em>) — "and he blotted out/wiped out" — <em>māḥāh</em>, the verb God announced in v. 4. The divine announcement (v. 4) and its execution (v. 23) use the same word, closing the narrative bracket. <strong>וַיִּשָּׁאֶר אַךְ-נֹחַ</strong> (<em>wayyiššāʾer ʾaḵ-nōaḥ</em>) — "only Noah remained" — the <em>ʾak</em> (only, nevertheless) marks the sole exception in a universal erasure. The verse structure mirrors the beginning: God made, God unmade; only Noah remained to begin again.</p>',
    "24": '<p><strong>חֲמִשִּׁים וּמְאַת יוֹם</strong> — "a hundred and fifty days." The waters prevailed (<em>gābar</em>, to be strong, prevail — the verb used of armies and power) for this duration before the wind of 8:1 reversed their course. The 150 days + the 40 days of rain = the full extent of the flood\'s height. The calendar precision (7:11 notes the 17th day of the 2nd month; 8:3-4 notes the 150 days ending with the ark resting on the 17th day of the 7th month) shows the author tracking the flood to the day.</p>'
  },
  "8": {
    "1": '<p><strong>וַיִּזְכֹּר אֱלֹהִים אֶת-נֹחַ</strong> (<em>wayyizkōr ʾĕlōhîm ʾet-nōaḥ</em>) — "but God remembered Noah." <em>Zākar</em> in the covenantal sense: not the recovery of forgotten information but the active, faithful engagement of God on behalf of the one he has committed himself to. The same verb marks every major covenant-rescue: God remembered Abraham and rescued Lot (19:29), God remembered Rachel and opened her womb (30:22), God remembered his covenant with Abraham/Isaac/Jacob and heard Israel\'s groaning (Exod 2:24; 6:5). "God remembered" is the turning-point formula in every crisis.</p><p><strong>וַיַּעֲבֵר אֱלֹהִים רוּחַ עַל-הָאָרֶץ</strong> (<em>wayyaʿăber ʾĕlōhîm rûaḥ ʿal-hāʾāreṣ</em>) — "and God caused a wind to pass over the earth." <em>Rûaḥ</em> (wind/spirit) echoes 1:2 (the Spirit of God hovering over the face of the waters). The same creative-breath that hovered over the primordial waters at the beginning now passes over the flood-waters to begin re-creation. The flood narrative frames itself as a new creation: the wind-over-waters at the start of both events is deliberate literary architecture.</p>',
    "2": '<p><strong>וַיִּסָּכְרוּ מַעְיְנֹת תְּהוֹם</strong> — "the fountains of the deep were stopped/closed." <em>Sākar</em> (Niphal, to be stopped, shut) — the reversal of 7:11 (<em>nibqĕʿû</em>, burst open). Both the <em>tĕhôm</em> (deep) and the heavenly windows are closed by divine action. The Hebrew passive (Niphal) keeps the agency implied rather than stated — the closing happens as the divine will reverses the opening. The rain ceasing (<em>kālaʾ</em>, to restrain, withhold) and the fountains closing happen simultaneously: the two sources of the flood are shut off together.</p>',
    "3": '<p><strong>וַיָּשֻׁבוּ הַמַּיִם מֵעַל הָאָרֶץ הָלוֹךְ וָשׁוֹב</strong> — "the waters returned from upon the earth, going and returning." The infinitive-absolute construction <em>hālôḵ wāšôb</em> (going and turning back — a progressive, gradual movement) expresses the manner of the water\'s recession: not sudden but steady and continuous. The same construction is used in Exod 15:19 (Pharaoh\'s horses going into the sea) — the infinitive absolute + finite verb gives the sense of ongoing, repeated action.</p>',
    "4": '<p>The ark resting on <strong>הָרֵי אֲרָרַט</strong> (<em>hārê ʾărāraṭ</em>) — "the mountains of Ararat." <em>Ararat</em> corresponds to the ancient kingdom of Urartu in what is now eastern Turkey/Armenia, around Lake Van. "Mountains of Ararat" (plural) suggests a mountain range rather than a single peak; the specific mountain (modern Mount Ararat = Ağrı Dağı, 5,137 m) was not identified as the ark\'s resting place until the medieval period. The seventeenth day of the seventh month: if the flood began on the 17th of the 2nd month (7:11), exactly 5 months (150 days) have elapsed, precisely matching v. 3\'s "hundred and fifty days."</p>',
    "5": '<p>The precise calendar notation continues: "the first day of the tenth month, the tops of the mountains became visible." The Hebrew verb <em>nīrĕʾû</em> (they were seen/appeared) is Niphal of <em>rāʾāh</em> — the mountains appear as the creation order reappears. The word <em>rāʾāh</em> is the verb used in 1:4 (God saw the light was good) and 1:10 (God saw the dry land) — creation\'s visibility is being restored.</p>',
    "6": '<p><strong>מִקֵּץ אַרְבָּעִים יוֹם</strong> — "at the end of forty days." The forty-day unit recurs from the flood\'s initiation (7:12, 17) — Noah waits a full forty days after the mountains appear before opening the window. The window (<em>ḥallôn</em>) that Noah opens is different from the window/hatch (<em>ṣōhar</em>, a light-opening in the roof, 6:16) that God specified; the text uses distinct vocabulary for the observation window opened at this point.</p>',
    "7": '<p><strong>אֶת-הָעֹרֵב</strong> (<em>ʾet-hāʿōrēb</em>) — "the raven." Ravens are unclean birds (Lev 11:15; Deut 14:14) and are scavengers who would have been drawn to floating carcasses — a possible reason why the raven does not return: it finds food on the floating dead. <strong>יָצוֹא וָשׁוֹב</strong> (<em>yāṣôʾ wāšôb</em>) — infinitive absolute + finite verb: the raven went "going and returning" continuously until the earth dried — it does not provide clean information about the flood\'s state.</p>',
    "8": '<p>The dove is sent to gather information the raven did not provide. <strong>יוֹנָה</strong> (<em>yônāh</em>) — "dove" — a clean bird (Lev 1:14; 5:7; 12:6, 8), associated with peace, love (Song 1:15; 2:14), and mourning (Isa 38:14; 59:11; Nah 2:7). The dove\'s return with the olive leaf (v. 11) will become an enduring symbol of peace and the earth\'s restoration — a meaning absent from the text but generated by the narrative\'s outcome.</p>',
    "9": '<p><strong>וְלֹא-מָצְאָה הַיּוֹנָה מָנוֹחַ לְכַף-רַגְלָהּ</strong> — "the dove found no resting place for the sole of her foot." <em>Mānoaḥ</em> (resting place, rest) — from <em>nûaḥ</em> (to rest), the root of Noah\'s name (5:29: "this one will comfort us... from our <em>nûaḥ</em>"). The dove seeking <em>mānoaḥ</em> (rest) echoes Noah\'s own name and the creation-rest of 2:1-3 — the dove\'s inability to find rest mirrors the earth\'s unreadiness to receive rest again.</p>',
    "10": '<p><strong>וַיָּחֶל עוֹד שִׁבְעַת יָמִים אֲחֵרִים</strong> — "and he waited yet another seven days." The seven-day interval recalls the seven-day wait before the flood began (7:4, 10) — Noah\'s patient observational discipline mirrors the structured waiting of the flood\'s onset. The Hiphil of <em>ḥûl</em> (to wait, to hold out) here: Noah actively holds himself in readiness rather than passively sitting.</p>',
    "11": '<p><strong>עֲלֵה-זַיִת טָרָף בְּפִיהָ</strong> — "a freshly plucked olive leaf in her beak." <em>Ṭārap</em> (torn off, freshly plucked — from the root meaning to tear fresh food) — the olive leaf is green and freshly obtained, not a floating dead fragment. Olive trees root in soil and their presence (still alive, still bearing leaves) indicates that the earth is surfacing and vegetation is growing again. <em>ʿAleh-zayit</em> (olive leaf/branch) will carry its symbolic weight of peace and restoration across cultures from this point, though the text itself is straightforwardly about ground-vegetation as the indicator of earth-recovery.</p>',
    "12": '<p><strong>לֹא-יָסְפָה שׁוּב-אֵלָיו עוֹד</strong> — "it did not return to him again." The dove\'s non-return is the definitive signal: the earth is habitable for birds, which means it is habitable for land creatures. The narrative economy is precise — the three-stage sending of the raven (no result), dove-return-empty, dove-return-with-leaf, dove-no-return — gives the reader a progressive revelation of earth\'s recovery that matches Noah\'s own information situation.</p>',
    "13": '<p><strong>וַיָּסַר נֹחַ אֶת-מִכְסֵה הַתֵּבָה</strong> — "Noah removed the covering of the ark." <em>Miḵsāh</em> (covering, roof covering) — the word is used for the tabernacle\'s covering (Exod 26:14; 35:11; 36:19). The removal of the covering makes the ark open to the sky above — an un-sealing after the sealing of 7:16. <strong>פְּנֵי הָאֲדָמָה</strong> — "the face/surface of the ground" — the same phrase used in 2:6 and throughout; the ground (ʾăḏāmāh) from which Adam was formed is now visible again, drying out.</p>',
    "14": '<p>The calendar precision completes: from 7:11 (17th day, 2nd month, year 600) to 8:14 (27th day, 2nd month, year 601) = exactly one year and ten days. The flood narrative operates with the precision of an annual calendar — 12 months (360 days by the 30-day month reckoning) plus the extra days. Some interpreters read a solar calendar of 364 days here. In any case, the narrative\'s calendrical specificity anchors the flood in datable time.</p>',
    "15": '<p>God\'s command to leave follows the same structure as God\'s command to enter (6:18-21; 7:1-3): divine speech initiating the major transition. Noah did not leave on his own initiative when he saw the ground was dry (v. 13) — he waited for the divine word. The obedience pattern of the entire flood narrative (Noah "did all that the LORD commanded him," 6:22; 7:5, 9, 16) reaches its final expression in waiting for the exit-command before exiting.</p>',
    "16": '<p><strong>צֵא מִן-הַתֵּבָה</strong> (<em>ṣēʾ min-hattēbāh</em>) — "go out from the ark" — the command uses the same imperative structure as the entrance command of 7:1 (<em>bōʾ</em>, come/enter). The chiastic correspondence between entry and exit mirrors the structural chiasm of the flood narrative as a whole: creation → un-creation → re-creation.</p>',
    "17": '<p><strong>הוֹצֵא אִתְּךָ כָּל-הַחַיָּה</strong> — "bring out with you all the living creatures." The Hiphil of <em>yāṣāʾ</em> (to cause to go out, bring out) — the same verb used for the Exodus (<em>yāṣāʾ</em> in Exod 13:3; 14:11; 20:2 and hundreds of other Exodus references). The repeated fruitfulness mandate — "be fruitful and teem on the earth, and be fruitful and multiply on the earth" — recycles the creation blessing of 1:22 (animals) and 1:28 (humanity), now re-issued to the post-flood world.</p>',
    "18": '<p>The exit is narrated with the same parallel structure as the entry (7:7, 13-16). The listing of Noah, his sons, his wife, and his sons\' wives mirrors 7:7 and 7:13 — the family unit is complete and intact. The repetition validates that God\'s preservation promise (6:18) was fully realized: the entire household survived.</p>',
    "19": '<p><strong>כֹּל הַחַיָּה כָּל-הָרֶמֶשׂ וְכָל-הָעוֹף כֹּל רוֹמֵשׂ עַל-הָאָרֶץ</strong> — the comprehensive listing of living creatures exiting the ark mirrors the creation sequence and the flood\'s comprehensive destruction. <em>Lĕmišpĕḥōtêhem</em> — "according to their families/clans" — a kinship-organizing term used in genealogical and census lists; the ark-exit is framed as the beginning of the new order of families and nations that ch. 10 will elaborate.</p>',
    "20": '<p><strong>מִזְבֵּחַ</strong> (<em>mizbēaḥ</em>) — "altar" — Noah builds the first explicitly named altar in the biblical narrative (the altars of Cain and Abel, 4:3-4, are implied but not named). <strong>מִכֹּל הַבְּהֵמָה הַטְּהֹרָה וּמִכֹּל הָעוֹף הַטָּהוֹר</strong> — "from every clean animal and every clean bird" — the clean/unclean distinction justified by the seven pairs of clean animals (7:2-3) is here revealed: the surplus was for sacrifice. Noah\'s first act upon leaving the ark is worship — the building of the altar and the offering of burnt offerings (<em>ʿōlōt</em>) establishes the post-flood world on the basis of sacrifice and worship rather than personal achievement.</p>',
    "21": '<p><strong>וַיָּרַח יְהוָה אֶת-רֵיחַ הַנִּיחֹחַ</strong> (<em>wayyāraḥ YHWH ʾet-rêaḥ hannîḥōaḥ</em>) — "and the LORD smelled the pleasing aroma." The anthropomorphic language is frank: God smells and is pleased. The term <em>rêaḥ hannîḥōaḥ</em> (aroma of rest/satisfaction) is the technical phrase used for the pleasing sacrifice smell throughout Leviticus and Numbers (Lev 1:9, 13, 17; 2:2, 9; 3:5; Num 15:3-24, etc.) — the Noahic sacrifice uses Levitical sacrificial vocabulary, grounding Sinai\'s cultic system in the post-flood covenant.</p><p><strong>יֵצֶר לֵב הָאָדָם רַע מִנְּעֻרָיו</strong> (<em>yēṣer lēb hāʾādām raʿ minĕʿūrāyw</em>) — "the inclination/impulse of the human heart is evil from his youth." <em>Yēṣer</em> (formation, inclination — from <em>yāṣar</em>, the potter\'s verb of 2:7) is the word used in 6:5 for the pre-flood judgment: "every <em>yēṣer</em> of the thoughts of his heart was only evil continually." The situation is unchanged: God promises never again to curse the ground because of humanity despite the same evil inclination that triggered the flood. The post-flood grace is explicitly given against the background of unchanged human nature — the covenant is not based on moral improvement but on divine commitment.</p>',
    "22": '<p><strong>עֹד כָּל-יְמֵי הָאָרֶץ</strong> — "while all the days of the earth remain." The temporal phrase frames the covenant of seedtime/harvest, cold/heat, summer/winter, day/night as conditional on the earth\'s endurance — not eternal in an absolute sense, but as long as the present world-order lasts. The six pairs (seed/harvest, cold/heat, summer/winter, day/night — plus implicitly the day/night pair) form the natural ordering of life: God commits to maintain the cosmic regularity that makes agriculture, seasons, and human life possible. This is not the Noahic covenant of ch. 9 (which involves blood and the rainbow sign) but a natural-order commitment that underlies it.</p>'
  },
  "9": {
    "1": '<p><strong>וַיְבָרֶךְ אֱלֹהִים אֶת-נֹחַ וְאֶת-בָּנָיו</strong> — "And God blessed Noah and his sons." The blessing formula repeats 1:28 exactly: <em>pĕrû ûrĕbû ûmilĕʾû ʾet-hāʾāreṣ</em> (be fruitful, multiply, fill the earth). The post-flood world begins with the same creation-blessing as the first world — Noah and his family are the second Adam, receiving the same mandate to multiply and fill. The repetition of the original blessing emphasizes continuity across the flood\'s discontinuity: creation\'s mandate stands.</p>',
    "2": '<p><strong>וּמוֹרַאֲכֶם וְחִתְּכֶם</strong> (<em>ûmôrăʾăḵem wĕḥittĕḵem</em>) — "your fear and your dread." The noun pair <em>môrāʾ</em> (fear, terror) and <em>ḥittāh</em> (dread, terror) describes the changed relationship between humanity and the animal kingdom. In 1:28 and 2:19-20 (the original creation mandate and the naming of animals), there is no mention of animal fear — the relationship was harmonious dominion. Now, after the Fall and Flood, the relationship is maintained by fear rather than natural co-operation. This is the realistic acknowledgment that the post-Fall world operates on power rather than harmony.</p>',
    "3": '<p><strong>כָּל-רֶמֶשׂ אֲשֶׁר הוּא-חַי לָכֶם יִהְיֶה לְאָכְלָה</strong> — "every moving thing that lives shall be food for you." The original food grant (1:29-30) limited humans to seed-bearing plants and fruit — meat was not permitted. Now God explicitly grants meat-eating: "just as I gave you the green plants, I give you everything." This is a new permission, not a clarification of an original permission. The grant is universal within the animal kingdom subject only to the blood restriction of v. 4.</p>',
    "4": '<p><strong>אַךְ-בָּשָׂר בְּנַפְשׁוֹ דָמוֹ לֹא תֹאכֵלוּ</strong> — "but flesh with its <em>nepeš</em> — its blood — you shall not eat." The contrastive particle <em>ʾaḵ</em> (but, however, only) marks the single exception to the universal food grant. The syntax is compressed: flesh + <em>bĕnaphšô</em> (in its life/soul) = <em>dāmô</em> (its blood). The equation <em>nepeš = dām</em> (life = blood) is spelled out explicitly in Lev 17:11 ("the life of the flesh is in the blood") and 17:14 ("the life of every creature is its blood"). The blood prohibition grounds the Levitical blood-atonement system (Lev 17:11: "I have given it to you on the altar to make atonement for your lives; it is the blood that makes atonement by the life") in the Noahic covenant — the blood belongs to God because life belongs to God.</p>',
    "5": '<p><strong>וְאַךְ אֶת-דִּמְכֶם לְנַפְשֹׁתֵיכֶם אֶדְרֹשׁ</strong> — "and surely for your blood I will require a reckoning, for your lives." <em>Dāraš</em> (to seek out, require, demand) is the legal-investigative term — God as the investigator of bloodshed. The accountability is from two sources: (1) from every animal (<em>miḵkol-ḥayyāh</em>) that kills a human — an extension of human accountability into the animal kingdom (cf. Exod 21:28-29, the goring ox); (2) from every human who kills another human. The structure expands the reach of divine justice beyond human-to-human violence.</p>',
    "6": '<p><strong>שֹׁפֵךְ דַּם הָאָדָם בָּאָדָם דָּמוֹ יִשָּׁפֵךְ</strong> — "whoever sheds the blood of a human (<em>hāʾādām</em>), by a human (<em>bāʾādām</em>) shall his blood be shed." The chiastic structure in Hebrew is formally perfect: <em>šōpēḵ dām hāʾādām / bāʾādām / dāmô yiššāpēḵ</em>. The three elements (blood + the human + blood) frame the middle term (by a human) — the punishment mirrors the crime in both substance (blood for blood) and agent (human for human). <strong>כִּי בְּצֶלֶם אֱלֹהִים עָשָׂה אֶת-הָאָדָם</strong> — "for in the image of God he made humankind." The <em>kî</em> (because, for) grounds the capital sanction in the image-of-God status: to murder a human is to assault God\'s image-representative on earth. Crucially, the image-of-God status is affirmed as still operative after the Fall and after the Flood — it was not destroyed by sin, only damaged or distorted.</p>',
    "7": '<p>The fruitfulness mandate of v. 1 is repeated verbatim — the divine speech brackets the blood laws (vv. 2-6) with the creation blessing (v. 1) and its restatement (v. 7). The structure: blessing → permitted food (v. 3) → forbidden food/blood (v. 4) → blood accountability (vv. 5-6) → blessing repeated. The repeating blessing frames the new laws as operating within the context of divine generosity and life-promotion, not mere restriction.</p>',
    "8": '<p>The divine speech of covenant-establishment begins with the double address: "God said to Noah and to his sons with him" — the covenant is addressed to both the immediate recipients (Noah) and the next generation (his sons). The covenant is dynastic and generational from its first formulation.</p>',
    "9": '<p><strong>אֲנִי הִנְנִי מֵקִים אֶת-בְּרִיתִי אִתְּכֶם</strong> — "I, behold, I am establishing my covenant with you." The emphatic independent pronoun <em>ʾănî</em> (I) + the demonstrative particle <em>hinnĕnî</em> (behold me/I am here) + Hiphil participle <em>mĕqîm</em> (establishing, making to stand) — the construction stresses both the divine person ("I myself") and the ongoing act (participle = continuous action). <em>Bĕrît</em> (covenant): this is the first time God explicitly calls his commitment a <em>bĕrît</em>; earlier commitments were present but the formal covenant terminology now appears. The covenant is unilateral in its establishment — God alone speaks and commits; Noah makes no oath.</p>',
    "10": '<p><strong>וְאֶת כָּל-נֶפֶשׁ הַחַיָּה</strong> — "and with every living creature (<em>nepeš</em>) that is with you." The Noahic covenant is unique among biblical covenants in being explicitly covenanted with non-human creatures — birds, livestock, and wild animals are all named as covenant parties (vv. 10, 12, 15, 16, 17). This is a cosmic covenant, not merely a human one; God\'s commitment is to all animate life bearing the <em>nepeš</em>. The Noahic covenant encompasses the entire creational order.</p>',
    "11": '<p><strong>לֹא-יִכָּרֵת כָּל-בָּשָׂר עוֹד מִמֵּי הַמַּבּוּל</strong> — "never again shall all flesh be cut off by the waters of a flood." The Niphal of <em>kārat</em> (to cut off, cut down — used for cutting covenants [<em>kārat bĕrît</em>, to cut a covenant] and for cutting off violators from the community) — ironically, the word for "cut off in judgment" is here used for the divine pledge that the ultimate judgment will never recur: never again shall flesh be "cut off" by flood. The double negative (<em>lōʾ... ʿôd</em>) emphasizes permanence: no more, not again.</p>',
    "12": '<p><strong>זֹאת אוֹת-הַבְּרִית</strong> (<em>zōʾt ʾôt-habbĕrît</em>) — "this is the sign of the covenant." <em>ʾÔt</em> (sign, mark) — the same word used for the Sabbath as a sign of the covenant (Exod 31:13, 17), circumcision as a sign (Gen 17:11), and the signs given through Moses (Exod 4:8-9; 10:1-2). Every major covenant has a sign; the Noahic sign is universal and cosmic — visible to all people, not requiring circumcision or Sabbath-keeping to observe.</p>',
    "13": '<p><strong>אֶת-קַשְׁתִּי נָתַתִּי בֶּעָנָן</strong> (<em>ʾet-qašti nātattî beʿānān</em>) — "I have set my bow in the clouds." <em>Qešet</em> means a bow — specifically, a warrior\'s bow used for shooting arrows. The same word is used of Nimrod\'s hunting prowess (10:9) and of the divine warrior\'s bow in Ps 7:12; Hab 3:9-11. By "setting the bow in the clouds," God hangs up his weapon of war — the bow is the ANE military symbol of divine judgment; a god who lays down the bow signals the cessation of war. God hangs his weapon in the sky as a visible reminder that the war of judgment is over. The rainbow is God\'s war-bow, decommissioned and displayed in the sky as a memorial of covenant peace.</p>',
    "14": '<p>The conditional clause structure — "when I bring clouds over the earth and the bow appears in the clouds" — makes the rainbow a periodic, repeated reminder rather than a one-time sign. The clouds (<em>ʿānān</em>) were associated with divine presence and theophany (Exod 13:21-22; 19:16-19; 1 Kgs 8:10-11; Ezek 1:4) — God\'s presence in the storm-cloud that might have brought flood is now the occasion for the bow\'s appearance, which interposes the covenant-reminder between the threatening cloud and the earth below.</p>',
    "15": '<p><strong>וְזָכַרְתִּי אֶת-בְּרִיתִי</strong> (<em>wĕzāḵartî ʾet-bĕrîtî</em>) — "and I will remember my covenant." <em>Zākar</em> again in the covenant-faithfulness sense (cf. 8:1). God does not forget the covenant, but the remembering-language places the covenant on the side of divine faithfulness rather than human performance — the rainbow reminds God (from the human narrative perspective) and humanity simultaneously. The waters will never again become a flood to destroy all flesh — <em>kol-bāśār</em> (all flesh): the comprehensive formula of vv. 11, 15, 16, 17 reinforces totality.</p>',
    "16": '<p><strong>בְּרִית עוֹלָם</strong> (<em>bĕrît ʿôlām</em>) — "an everlasting covenant." <em>ʿÔlām</em> (eternity, perpetuity, from of old and into the far future) qualifies the covenant as without temporal limit. The same phrase is used for the Abrahamic covenant (17:7, 13, 19), the Mosaic covenant in its application (Exod 31:16; Lev 24:8), and the Davidic covenant (2 Sam 23:5; Ps 89:28). The Noahic covenant is the most universally inclusive of all biblical covenants — it encompasses all living creatures and all generations.</p>',
    "17": '<p>God reiterates the sign-identification for clarity: "This is the sign of the covenant I have established between me and all flesh that is on the earth." The verse closes the covenant-establishment speech with a summary statement, a standard narrative technique (the "colophon" that closes a section by restating its content). The triple use of <em>bĕrît</em> (covenant) in this verse (in the Hebrew: <em>haqqeṣet... bĕrît... bêynî ûbêyn kol-bāśār</em>) reinforces the covenant\'s centrality to this entire section.</p>',
    "18": '<p><strong>חָם הוּא אֲבִי כְנָעַן</strong> (<em>ḥām hûʾ ʾăbî kĕnaʿan</em>) — "Ham was the father of Canaan." The parenthetical identification of Ham as Canaan\'s father anticipates the curse of v. 25 — the reader is being prepared by noting the connection between Ham and Canaan before the incident that will curse Canaan. The three sons of Noah (Shem, Ham, Japheth) are the ancestors of the nations in ch. 10, giving the Ham/Canaan/curse narrative its geopolitical implications for Israel\'s later relationship with Canaan.</p>',
    "19": '<p><strong>מֵאֵלֶּה נָפְצָה כָל-הָאָרֶץ</strong> (<em>mēʾēlleh nāpĕṣāh kol-hāʾāreṣ</em>) — "from these the whole earth was scattered/spread out." <em>Nāpaṣ</em> (to scatter, spread) — the same verb as in the Babel narrative (11:4, 8, 9), where God scatters the nations. The "spreading out" here is the positive peopling of the earth fulfilling the creation mandate; the scattering of Babel will be its divinely-imposed intensification. The bridge between the Noahic genealogical promise and the Babel dispersion runs through this verse.</p>',
    "20": '<p><strong>וַיָּחֶל נֹחַ אִישׁ הָאֲדָמָה</strong> (<em>wayyāḥel nōaḥ ʾîš hāʾăḏāmāh</em>) — "Noah, a man of the soil, began." <em>Hēḥēl</em> is the Hiphil of <em>ḥālal</em> — "began" or "profaned/desecrated." The same form can mean either "began" or "made common/profane" (cf. 4:26: <em>hûḥal</em>, "at that time people began to call on the name of the LORD"). The ambiguity may be intentional: Noah began as a man of the ground, or Noah, a man of the ground, profaned himself. <em>ʾÎš hāʾăḏāmāh</em> (man of the soil) is the same construction as <em>ʾādām min-hāʾăḏāmāh</em> (Adam from the ground, 2:7; 3:19) — Noah is the new Adam, returning to work the ground.</p>',
    "21": '<p><strong>וַיִּשְׁתְּ מִן-הַיַּיִן וַיִּשְׁכָּר</strong> — "and he drank from the wine and became drunk." The verb <em>šākar</em> (to become drunk) is used neutrally here — no explicit moral judgment on the drunkenness itself. <strong>וַיִּתְגַּל</strong> (<em>wayyitgal</em>) — "and he uncovered himself" — Hithpael of <em>gālāh</em> (to uncover, reveal). The reflexive (Hithpael) makes this self-exposure: Noah uncovered himself within his tent. The nakedness (<em>ʿerwāh</em> implied) connects back to 2:25 and 3:7 — nakedness in the biblical world is associated with vulnerability, shame, and violation.</p>',
    "22": '<p><strong>וַיַּרְא חָם אֲבִי כְנָעַן אֵת עֶרְוַת אָבִיו</strong> — "Ham, the father of Canaan, saw the nakedness of his father." <em>Rāʾāh ʿerwāh</em> (to see nakedness) is the legal phrase in Lev 20:17-19 for forbidden sexual viewing/violation — "if a man takes his sister... and sees her nakedness (<em>rāʾāh ʾet-ʿerwātāh</em>)... it is a disgrace." The phrase in Leviticus consistently connotes sexual transgression, not accidental observation. The mildest interpretation (Ham accidentally saw, then gossiped about it to his brothers) does not fully account for the severity of the curse on Canaan or the use of this specific technical phrase. At minimum, Ham violated his father\'s dignity by observing and reporting rather than covering; at maximum, the phrase implies a more serious violation. The text leaves the specific act deliberately ambiguous.</p>',
    "23": '<p><strong>וַיִּקַּח שֵׁם וָיֶפֶת אֶת-הַשִּׂמְלָה</strong> — "Shem and Japheth took a garment." The contrast is explicit: Ham saw and told; Shem and Japheth took a garment and covered. <strong>עַל-שְׁכֶם שְׁנֵיהֶם</strong> (<em>ʿal-šĕkem šĕnêhem</em>) — "on the shoulders of both of them" — both carry the garment together, walking backward (<em>wayyĕlĕḵû ʾăḥōranît</em>) so as not to see their father\'s nakedness. The backward-walking detail is not merely practical but honor-protective: they refuse even accidental sight. Their act of covering reverses Ham\'s act of exposing — shame covered vs. shame revealed.</p>',
    "24": '<p><strong>מַה-עָּשָׂה לוֹ בְּנוֹ הַקָּטָן</strong> — "what his youngest son had done to him." The narrative describes Ham as the "youngest son" — but in the standard genealogical list, Ham is the middle son (Shem, Ham, Japheth in 5:32; 6:10; 7:13; 9:18; 10:1). Either "youngest" (<em>qāṭōn</em>) refers to relative status or honor-position in this context rather than birth order, or there is a tradition that Ham was in fact the youngest. Noah\'s "finding out what his son had done" implies that what Ham did was a discovered act, not merely observed — the detail that Shem and Japheth specifically did not see their father (v. 23) implies that what there was to see was something shameful that Ham saw (and possibly did).</p>',
    "25": '<p><strong>אָרוּר כְּנָעַן</strong> (<em>ʾārûr kĕnaʿan</em>) — "cursed be Canaan." The curse falls on Canaan, Ham\'s son, rather than on Ham directly. The explanation commonly offered: cursing the son rather than the father may reflect the ancient Near Eastern legal-rhetorical convention in which the consequences of a father\'s sin fall on his lineage (cf. Exod 20:5), or may reflect that Ham\'s sin was done through Canaan (the text is silent on this). Theologically significant: the curse does not fall on Shem or Japheth\'s descendants, shaping the later Israelite understanding of Canaan\'s relationship to Israel. <em>ʿEbed ʿăbādîm</em> — "servant of servants" — the superlative construction (like "holy of holies" = most holy, "king of kings" = supreme king) means "the lowest possible servant," the ultimate subordinate.</p>',
    "26": '<p><strong>בָּרוּךְ יְהוָה אֱלֹהֵי שֵׁם</strong> — "Blessed be the LORD, the God of Shem." The blessing of Shem is structured as a blessing of God who is Shem\'s God — the covenantal name <em>YHWH</em> appears here, connecting Shem\'s line with the covenant name. The Messianic line running through Shem (to Abraham, to Israel, to Christ) makes this blessing the covenantal promise: the LORD-covenanted God is the God of Shem\'s descendants. Canaan is servant to Shem — implying Israel\'s eventual conquest of Canaan under Joshua.</p>',
    "27": '<p><strong>יַפְתְּ אֱלֹהִים לְיֶפֶת</strong> (<em>yapet ʾĕlōhîm lĕyepet</em>) — "May God enlarge Japheth." The wordplay is explicit: <em>yāpat</em> (enlarge, make wide) on Japheth (<em>yepet</em>). The blessing of Japheth is territorial expansion (<em>pāṭāh</em> = to be wide, open). <strong>וְיִשְׁכֹּן בְּאָהֳלֵי-שֵׁם</strong> — "and let him dwell in the tents of Shem." The subject of "dwell" is ambiguous: either Japheth dwells in Shem\'s tents (a sign of blessing — sharing the covenant space), or God dwells in Shem\'s tents (God\'s presence among Shem\'s descendants). The ambiguity is interpretively productive: both readings are theologically rich.</p>',
    "28": '<p>The genealogical framing verse closes the Noahic narrative. <strong>וַיְחִי-נֹחַ אַחַר הַמַּבּוּל</strong> — "Noah lived after the flood." The <em>wayyiqtol</em> marks the narrative continuation into the genealogical register. Noah lives 350 more years after the flood — his total of 950 years (v. 29) makes him the second-longest-lived of the antediluvian patriarchs (only Methuselah at 969 years exceeds him). The post-flood lifespans begin declining in ch. 11, marking the transition from the antediluvian world-era to the patriarchal era.</p>',
    "29": '<p><strong>וַיָּמֹת</strong> (<em>wayyāmōt</em>) — "and he died." The genealogical death formula closes the Noahic narrative. The structure of ch. 5 (so-and-so lived X years, fathered Y, lived Z more years, and he died) is here abbreviated to the death notice only. Noah stands at the pivot of the flood narrative: the last of the antediluvian patriarchs, the first man of the post-flood world, the one through whom all humanity descends after the flood. His death closes the flood narrative and opens the space for the Table of Nations (ch. 10) and Babel (ch. 11).</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'genesis')
    merge_comm(existing, GENESIS)
    save_comm('mkt-original', 'genesis', existing)
    print('Genesis 7-9 mkt-original written.')

if __name__ == '__main__':
    main()
